import React from 'react';
import { formatBillions, formatMillions } from '../utils/currency';

const RegionalBreakdown = ({ regions, onRegionClick, selectedRegion }) => {

  const n = (v) => parseFloat(v || 0);
  const fmt = (v, decimals = 1) => n(v).toFixed(decimals);

  const getRiskColor = (score) => {
    const s = n(score);
    if (s >= 6) return '#EF4444';
    if (s >= 4) return '#F59E0B';
    return '#22C55E';
  };

  const getRegionColor = (region) => {
    const colorMap = {
      'United States':       '#FF5F02',
      'Europe':              '#3B82F6',
      'Asia-Pacific Africa': '#06B6D4',
      'W Hemisphere Ex-US':  '#8B5CF6',
    };
    return colorMap[region] || '#6B7280';
  };

  const maxPipeline = Math.max(...regions.map(r => n(r.pipeline_billions)), 1);
  const maxRisk     = Math.max(...regions.map(r => n(r.revenue_at_risk_millions)), 1);
  const maxAccel    = Math.max(...regions.map(r => n(r.accel_90d_millions)), 1);

  const totals = {
    pipeline:  regions.reduce((s, r) => s + n(r.pipeline_billions), 0),
    atRisk:    regions.reduce((s, r) => s + n(r.revenue_at_risk_millions), 0),
    accel90:   regions.reduce((s, r) => s + n(r.accel_90d_millions), 0),
    subs:      regions.reduce((s, r) => s + n(r.submission_count), 0),
  };

  return (
    <div style={{ padding: '0 24px 24px' }}>
      <div style={{ marginBottom: 12 }}>
        <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: '0.1em', color: '#9CA3AF', textTransform: 'uppercase' }}>
          Regional Pipeline Breakdown — click to filter
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: 12 }}>

        {regions.map((region) => {
          const isSelected = selectedRegion === region.Global_Region;
          const color = getRegionColor(region.Global_Region);
          const riskColor = getRiskColor(region.avg_risk_score);
          const pipelinePct = (n(region.pipeline_billions) / maxPipeline) * 100;
          const riskPct     = (n(region.revenue_at_risk_millions) / maxRisk) * 100;
          const accelPct    = (n(region.accel_90d_millions) / maxAccel) * 100;

          return (
            <div
              key={region.Global_Region}
              onClick={() => onRegionClick(isSelected ? 'all' : region.Global_Region)}
              style={{
                background: isSelected ? '#1a1a2e' : '#111827',
                border: `2px solid ${isSelected ? color : '#1F2937'}`,
                borderRadius: 8,
                padding: '14px 16px',
                cursor: 'pointer',
                transition: 'all 0.15s ease',
              }}
            >
              {/* Region name + filter indicator */}
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
                <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: '0.08em', color: color, textTransform: 'uppercase' }}>
                  {region.Global_Region}
                </div>
                {isSelected && <div style={{ fontSize: 9, color: color, border: `1px solid ${color}`, borderRadius: 3, padding: '1px 5px' }}>FILTERED</div>}
              </div>

              {/* Pipeline */}
              <div style={{ marginBottom: 8 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
                  <span style={{ fontSize: 10, color: '#6B7280' }}>Pipeline</span>
                  <span style={{ fontSize: 12, fontWeight: 700, color: '#F9FAFB' }}>{formatBillions(region.pipeline_billions)}</span>
                </div>
                <div style={{ height: 4, background: '#1F2937', borderRadius: 2 }}>
                  <div style={{ height: '100%', width: `${pipelinePct}%`, background: color, borderRadius: 2 }} />
                </div>
              </div>

              {/* Revenue at risk */}
              <div style={{ marginBottom: 8 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
                  <span style={{ fontSize: 10, color: '#6B7280' }}>At Risk</span>
                  <span style={{ fontSize: 12, fontWeight: 700, color: '#EF4444' }}>{formatMillions(region.revenue_at_risk_millions)}</span>
                </div>
                <div style={{ height: 4, background: '#1F2937', borderRadius: 2 }}>
                  <div style={{ height: '100%', width: `${riskPct}%`, background: '#EF4444', borderRadius: 2, opacity: 0.7 }} />
                </div>
              </div>

              {/* 90-day acceleration opportunity */}
              <div style={{ marginBottom: 10 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
                  <span style={{ fontSize: 10, color: '#6B7280' }}>90d Opportunity</span>
                  <span style={{ fontSize: 12, fontWeight: 700, color: '#22C55E' }}>{formatMillions(region.accel_90d_millions)}</span>
                </div>
                <div style={{ height: 4, background: '#1F2937', borderRadius: 2 }}>
                  <div style={{ height: '100%', width: `${accelPct}%`, background: '#22C55E', borderRadius: 2, opacity: 0.7 }} />
                </div>
              </div>

              {/* Footer stats */}
              <div style={{ display: 'flex', justifyContent: 'space-between', paddingTop: 8, borderTop: '1px solid #1F2937' }}>
                <div style={{ textAlign: 'center' }}>
                  <div style={{ fontSize: 14, fontWeight: 700, color: '#F9FAFB' }}>{region.submission_count}</div>
                  <div style={{ fontSize: 9, color: '#6B7280' }}>Submissions</div>
                </div>
                <div style={{ textAlign: 'center' }}>
                  <div style={{ fontSize: 14, fontWeight: 700, color: riskColor }}>{fmt(region.avg_risk_score)}</div>
                  <div style={{ fontSize: 9, color: '#6B7280' }}>Avg Risk</div>
                </div>
              </div>
            </div>
          );
        })}

        {/* All Regions / Clear button */}
        <div
          onClick={() => onRegionClick('all')}
          style={{
            background: selectedRegion === 'all' ? '#1a1a2e' : '#111827',
            border: `2px solid ${selectedRegion === 'all' ? '#FF5F02' : '#374151'}`,
            borderRadius: 8,
            padding: '14px 16px',
            cursor: 'pointer',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'space-between',
          }}
        >
          <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: '0.08em', color: selectedRegion === 'all' ? '#FF5F02' : '#9CA3AF', textTransform: 'uppercase', marginBottom: 10 }}>
            {selectedRegion === 'all' ? '✓ All Regions' : 'All Regions'}
          </div>

          <div style={{ marginBottom: 6 }}>
            <div style={{ fontSize: 10, color: '#6B7280', marginBottom: 2 }}>Total Pipeline</div>
            <div style={{ fontSize: 20, fontWeight: 800, color: '#F9FAFB' }}>{formatBillions(totals.pipeline)}</div>
          </div>

          <div style={{ marginBottom: 6 }}>
            <div style={{ fontSize: 10, color: '#6B7280', marginBottom: 2 }}>Total At Risk</div>
            <div style={{ fontSize: 16, fontWeight: 700, color: '#EF4444' }}>{formatMillions(totals.atRisk)}</div>
          </div>

          <div style={{ marginBottom: 10 }}>
            <div style={{ fontSize: 10, color: '#6B7280', marginBottom: 2 }}>90d Opportunity</div>
            <div style={{ fontSize: 16, fontWeight: 700, color: '#22C55E' }}>{formatMillions(totals.accel90)}</div>
          </div>

          <div style={{ paddingTop: 8, borderTop: '1px solid #1F2937' }}>
            <div style={{ fontSize: 14, fontWeight: 700, color: '#F9FAFB' }}>
              {totals.subs} <span style={{ fontSize: 10, color: '#6B7280', fontWeight: 400 }}>submissions</span>
            </div>
            <div style={{ fontSize: 11, color: '#6B7280', marginTop: 4 }}>{regions.length} regions tracked</div>
          </div>
        </div>

      </div>
    </div>
  );
};

export default RegionalBreakdown;
